fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    let k = k as usize;
    let mut left = 0;
    let mut right = edges.iter().map(|e| e[2]).max().unwrap_or(0);
    let mut sorted_edges = edges.clone();
    sorted_edges.sort_by_key(|e| e[2]);

    // Check if it's possible to have all components with max cost <= mid
    let is_possible = |mid: i64| -> bool {
        let mut parent: Vec<usize> = (0..n).collect();
        let mut rank = vec![0; n];
        let mut components = n;

        fn find(parent: &mut Vec<usize>, u: usize) -> usize {
            if parent[u] != u {
                parent[u] = find(parent, parent[u]);
            }
            parent[u]
        }

        fn union(parent: &mut Vec<usize>, rank: &mut Vec<usize>, u: usize, v: usize) -> bool {
            let u_root = find(parent, u);
            let v_root = find(parent, v);
            if u_root == v_root {
                return false;
            }
            if rank[u_root] < rank[v_root] {
                parent[u_root] = v_root;
            } else if rank[u_root] > rank[v_root] {
                parent[v_root] = u_root;
            } else {
                parent[v_root] = u_root;
                rank[u_root] += 1;
            }
            true
